void load_bias_1::thread_ap_clk_no_reset_() {
    if ( ap_rst.read() == ap_const_logic_1) {
        ap_CS_fsm = ap_ST_fsm_state1;
    } else {
        ap_CS_fsm = ap_NS_fsm.read();
    }
    if ( ap_rst.read() == ap_const_logic_1) {
        ap_enable_reg_pp0_iter0 = ap_const_logic_0;
    } else {
        if ((esl_seteq<1,1,1>(ap_const_logic_1, ap_CS_fsm_pp0_stage0.read()) && 
             esl_seteq<1,1,1>(ap_block_pp0_stage0_subdone.read(), ap_const_boolean_0) && 
             esl_seteq<1,1,1>(ap_const_logic_1, ap_condition_pp0_exit_iter0_state2.read()))) {
            ap_enable_reg_pp0_iter0 = ap_const_logic_0;
        } else if ((esl_seteq<1,1,1>(ap_const_logic_1, ap_CS_fsm_state1.read()) && 
                    esl_seteq<1,1,1>(ap_start.read(), ap_const_logic_1))) {
            ap_enable_reg_pp0_iter0 = ap_const_logic_1;
        }
    }
    if ( ap_rst.read() == ap_const_logic_1) {
        ap_enable_reg_pp0_iter1 = ap_const_logic_0;
    } else {
        if (esl_seteq<1,1,1>(ap_block_pp0_stage0_subdone.read(), ap_const_boolean_0)) {
            if (esl_seteq<1,1,1>(ap_const_logic_1, ap_condition_pp0_exit_iter0_state2.read())) {
                ap_enable_reg_pp0_iter1 = (ap_condition_pp0_exit_iter0_state2.read() ^ ap_const_logic_1);
            } else if (esl_seteq<1,1,1>(ap_const_boolean_1, ap_const_boolean_1)) {
                ap_enable_reg_pp0_iter1 = ap_enable_reg_pp0_iter0.read();
            }
        }
    }
    if ( ap_rst.read() == ap_const_logic_1) {
        ap_enable_reg_pp0_iter2 = ap_const_logic_0;
    } else {
        if (esl_seteq<1,1,1>(ap_block_pp0_stage0_subdone.read(), ap_const_boolean_0)) {
            ap_enable_reg_pp0_iter2 = ap_enable_reg_pp0_iter1.read();
        } else if ((esl_seteq<1,1,1>(ap_const_logic_1, ap_CS_fsm_state1.read()) && 
                    esl_seteq<1,1,1>(ap_start.read(), ap_const_logic_1))) {
            ap_enable_reg_pp0_iter2 = ap_const_logic_0;
        }
    }
    if ((esl_seteq<1,1,1>(ap_const_logic_1, ap_CS_fsm_pp0_stage0.read()) && 
         esl_seteq<1,1,1>(ap_block_pp0_stage0_11001.read(), ap_const_boolean_0) && 
         esl_seteq<1,1,1>(icmp_ln70_reg_372.read(), ap_const_lv1_0) && 
         esl_seteq<1,1,1>(ap_const_logic_1, ap_enable_reg_pp0_iter1.read()))) {
        i_0_reg_274 = i_reg_376.read();
    } else if ((esl_seteq<1,1,1>(ap_const_logic_1, ap_CS_fsm_state1.read()) && 
                esl_seteq<1,1,1>(ap_start.read(), ap_const_logic_1))) {
        i_0_reg_274 = ap_const_lv8_0;
    }
    if ((esl_seteq<1,1,1>(ap_const_logic_1, ap_CS_fsm_state1.read()) && esl_seteq<1,1,1>(ap_start.read(), ap_const_logic_1))) {
        bias_buff_0_V_addr_reg_332 =  (sc_lv<7>) (zext_ln73_fu_296_p1.read());
        bias_buff_1_V_addr_reg_337 =  (sc_lv<7>) (zext_ln73_fu_296_p1.read());
        bias_buff_2_V_addr_reg_342 =  (sc_lv<7>) (zext_ln73_fu_296_p1.read());
        bias_buff_3_V_addr_reg_347 =  (sc_lv<7>) (zext_ln73_fu_296_p1.read());
        bias_buff_4_V_addr_reg_352 =  (sc_lv<7>) (zext_ln73_fu_296_p1.read());
        bias_buff_5_V_addr_reg_357 =  (sc_lv<7>) (zext_ln73_fu_296_p1.read());
        bias_buff_6_V_addr_reg_362 =  (sc_lv<7>) (zext_ln73_fu_296_p1.read());
        bias_buff_7_V_addr_reg_367 =  (sc_lv<7>) (zext_ln73_fu_296_p1.read());
    }
    if ((esl_seteq<1,1,1>(ap_const_logic_1, ap_CS_fsm_pp0_stage0.read()) && esl_seteq<1,1,1>(ap_block_pp0_stage0_11001.read(), ap_const_boolean_0) && esl_seteq<1,1,1>(icmp_ln70_reg_372.read(), ap_const_lv1_0))) {
        bias_buff_0_V_load_reg_381 = bias_buff_0_V_q0.read();
        bias_buff_1_V_load_reg_386 = bias_buff_1_V_q0.read();
        bias_buff_2_V_load_reg_391 = bias_buff_2_V_q0.read();
        bias_buff_3_V_load_reg_396 = bias_buff_3_V_q0.read();
        bias_buff_4_V_load_reg_401 = bias_buff_4_V_q0.read();
        bias_buff_5_V_load_reg_406 = bias_buff_5_V_q0.read();
        bias_buff_6_V_load_reg_411 = bias_buff_6_V_q0.read();
        bias_buff_7_V_load_reg_416 = bias_buff_7_V_q0.read();
    }
    if ((esl_seteq<1,1,1>(ap_const_logic_1, ap_CS_fsm_pp0_stage0.read()) && esl_seteq<1,1,1>(ap_block_pp0_stage0_11001.read(), ap_const_boolean_0))) {
        i_0_reg_274_pp0_iter1_reg = i_0_reg_274.read();
        icmp_ln70_reg_372 = icmp_ln70_fu_308_p2.read();
        icmp_ln70_reg_372_pp0_iter1_reg = icmp_ln70_reg_372.read();
    }
    if ((esl_seteq<1,1,1>(ap_const_logic_1, ap_CS_fsm_pp0_stage0.read()) && esl_seteq<1,1,1>(ap_block_pp0_stage0_11001.read(), ap_const_boolean_0) && esl_seteq<1,1,1>(ap_const_logic_1, ap_enable_reg_pp0_iter0.read()))) {
        i_reg_376 = i_fu_314_p2.read();
    }
}

